import { useContext, useEffect } from "react";
import { Table, Container, Card } from "react-bootstrap";
import UserContext from "./context";
import axios from "axios";

export default function TransactionHistory() {
    const { user, setUser } = useContext(UserContext);

    useEffect(() => {
        const fetchLatestData = async () => {
            try {
                const res = await axios.get('http://localhost:8080/api/users/profile');
                setUser(res.data);
            } catch (err) {
                console.error("Error fetching latest transactions:", err);
            }
        };
        if (user) fetchLatestData();
    }, []);

    if (!user) return <Container className="mt-5"><h3>Please login to view your transaction history.</h3></Container>;

    const totalIncome = user.transactions
        ?.filter(tx => tx.type === 'deposit')
        .reduce((sum, tx) => sum + tx.amount, 0) || 0;

    const totalExpense = user.transactions
        ?.filter(tx => tx.type === 'withdraw')
        .reduce((sum, tx) => sum + tx.amount, 0) || 0;

    return (
        <Container className="my-5">
            <div className="tracking-summary-container">
                <div className="stat-widget">
                    <span className="stat-widget-label">Total Deposits</span>
                    <span className="stat-widget-value value-income">₹{totalIncome.toLocaleString()}</span>
                </div>
                <div className="stat-widget">
                    <span className="stat-widget-label">Total Withdrawals</span>
                    <span className="stat-widget-value value-expense">₹{totalExpense.toLocaleString()}</span>
                </div>
                <div className="stat-widget" style={{ borderLeft: "4px solid #3498db" }}>
                    <span className="stat-widget-label">Net Balance</span>
                    <span className="stat-widget-value value-balance">₹{user.amount.toLocaleString()}</span>
                </div>
            </div>

            <Card className="shadow-lg tracking-card">
                <Card.Header className="bg-white border-0 py-4 px-4 overflow-hidden">
                    <div className="d-flex justify-content-between align-items-center">
                        <div>
                            <h3 className="fw-bold mb-0 text-dark">Transaction Statement</h3>
                            <p className="text-muted mb-0 small text-uppercase tracking-wider">Statement for {user.name}</p>
                        </div>
                        <div className="text-end">
                            <span className="badge bg-light text-dark border p-2">Acc ID: #{user._id.slice(-6).toUpperCase()}</span>
                        </div>
                    </div>
                </Card.Header>
                <Card.Body className="px-4 pb-4">
                    <Table responsive className="history-table mb-0">
                        <thead>
                            <tr>
                                <th>Transaction Detail</th>
                                <th>Type</th>
                                <th className="text-end">Amount</th>
                                <th className="text-end">Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            {user.transactions && user.transactions.length > 0 ? (
                                user.transactions.slice().reverse().map((tx, index) => (
                                    <tr key={index} className="history-row">
                                        <td>
                                            <div className="d-flex align-items-center">
                                                <div className={`tx-type-icon ${tx.type === 'deposit' ? 'icon-deposit' : 'icon-withdraw'}`}>
                                                    <i className={`bi ${tx.type === 'deposit' ? 'bi-arrow-down-left' : 'bi-arrow-up-right'}`}></i>
                                                </div>
                                                <div>
                                                    <div className="fw-bold text-dark">{tx.type === 'deposit' ? 'Funds Received' : 'Funds Withdrawn'}</div>
                                                    <div className="tx-date">{new Date(tx.date).toLocaleDateString()} • {new Date(tx.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`badge ${tx.type === 'deposit' ? 'bg-success-subtle text-success' : 'bg-danger-subtle text-danger'} rounded-pill px-3`}>
                                                {tx.type.toUpperCase()}
                                            </span>
                                        </td>
                                        <td className="text-end">
                                            <span className={`tx-amount ${tx.type === 'deposit' ? 'text-success' : 'text-danger'}`}>
                                                {tx.type === 'deposit' ? '+' : '-'} ₹{tx.amount.toLocaleString()}
                                            </span>
                                        </td>
                                        <td className="text-end">
                                            <span className="text-success small fw-bold">COMPLETED</span>
                                        </td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan="4" className="py-5 text-center text-muted">
                                        <i className="bi bi-info-circle me-2"></i>No transaction history found for this account.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </Table>
                </Card.Body>
            </Card>
        </Container>
    );
}
